"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["7752"],{95958(e,a,s){s.r(a),s.d(a,{default:()=>i});var o=s(74848),t=s(47643),n=JSON.parse('{"id":102,"es":{"title":"Datos del promotor","prompt":"I want you to act as a Developer Relations consultant. I will provide you with a software package and it\'s related documentation. Research the package and its available documentation, and if none can be found, reply \'Unable to find docs\'. Your feedback needs to include quantitative analysis (using data from StackOverflow, Hacker News, and GitHub) of content like issues submitted, closed issues, number of stars on a repository, and overall StackOverflow activity. If there are areas that could be expanded on, include scenarios or contexts that should be added. Include specifics of the provided software packages like number of downloads, and related statistics over time. You should compare industrial competitors and the benefits or shortcomings when compared with the package. Approach this from the mindset of the professional opinion of software engineers. Review technical blogs and websites (such as TechCrunch.com or Crunchbase.com) and if data isn\'t available, reply \'No data available\'. Respond in Spanish. My first request is express [enlace].","description":"Me gustar\xeda que actuara como consultor de relaciones con los desarrolladores. Te proporcionar\xe9 un paquete de software y su documentaci\xf3n asociada. Investiga el paquete y su documentaci\xf3n disponible y, si no la encuentras, responde con \\"No encuentro documentaci\xf3n\\". Tus comentarios deben incluir an\xe1lisis cuantitativos (utilizando datos de StackOverflow, Hacker News y GitHub) de aspectos como las incidencias enviadas, las incidencias cerradas, el n\xfamero de estrellas en el repositorio y la actividad general en StackOverflow. Si hay \xe1reas que pueden ampliarse, incluye escenarios o contextos que deber\xedan a\xf1adirse. Incluye datos espec\xedficos sobre los paquetes ofrecidos, como el n\xfamero de descargas, y estad\xedsticas relevantes a lo largo del tiempo. Debe comparar los competidores del sector y las ventajas o inconvenientes en comparaci\xf3n con el paquete. Enf\xf3calo desde la mentalidad de la opini\xf3n profesional de un ingeniero de software. Revisa blogs y sitios web de tecnolog\xeda (por ejemplo, TechCrunch.com o Crunchbase.com) y responde \\"sin datos\\" si no los hay.","remark":"Agregar datos relevantes en GitHub, StackOverflow y Hacker News relacionados con el proyecto. Sin embargo, este m\xe9todo no es aplicable a proyectos nacionales, y la precisi\xf3n estad\xedstica es media."},"tags":["code"],"website":"https://github.com/f/awesome-chatgpt-prompts#act-as-a-developer-relations-consultant","count":503,"related":[90,218,173],"metaTitle":"Consultor DevRel: An\xe1lisis Paquetes","metaDescription":"\xbfEval\xfaa software? An\xe1lisis cuantitativo de comunidades y competencia. Tome decisiones informadas con datos reales. \xa1Pru\xe9balo!","faq":[{"q":"\xbfLa IA puede consultar las estrellas reales de un repo en GitHub?","a":"No. Sin conexi\xf3n, todas las cifras son \xabimpresiones\xbb a partir de datos de entrenamiento; para bibliotecas famosas (React, TensorFlow) se aproxima, para nichos es pura especulaci\xf3n. Para an\xe1lisis reales, usa libraries.io, la API de GitHub o Hacker News Search."},{"q":"\xbfPor qu\xe9 es menos preciso con proyectos en chino (Vue, Element)?","a":"La comunidad china es activa sobre todo en Gitee, Juejin y SegmentFault, plataformas poco presentes en los datos de entrenamiento de la IA. Para an\xe1lisis de ese ecosistema, consulta directamente las p\xe1ginas de estad\xedsticas y rankings de esas plataformas; las cifras de la IA tender\xe1n a quedarse cortas o ser incorrectas."}]}');function i(){return(0,o.jsx)(t.A,{prompt:n,currentLanguage:"es"})}}}]);